class CountUpLite{constructor(el,end,duration=1300){this.el=el;this.end=Number(end)||0;this.startValue=Number(el.dataset.start)||0;this.suffix=el.dataset.suffix||"";this.group=el.dataset.group!=="false";this.duration=duration}start(){const start=performance.now();const range=this.end-this.startValue;const tick=now=>{const p=Math.min((now-start)/this.duration,1);const eased=1-Math.pow(1-p,3);const value=Math.floor(this.startValue+range*eased);this.el.textContent=(this.group?value.toLocaleString():String(value))+this.suffix;if(p<1)requestAnimationFrame(tick)};requestAnimationFrame(tick)}}
